import { writeFileSync, appendFileSync } from 'node:fs';
import { setTimeout as delay } from 'node:timers/promises';

const taskDir = '/tmp/codexdesktop-tasks/electron-webcontentsview-linux-wayland-issues';
const evidencePath = `${taskDir}/evidence.jsonl`;
const metricsPath = `${taskDir}/metrics.json`;

const headers = {
  'Accept': 'application/vnd.github+json',
  'User-Agent': 'codexdesktop-electron-issue-research'
};

const queries = [
  'repo:electron/electron is:issue is:open WebContentsView Linux',
  'repo:electron/electron is:issue is:open WebContentsView Wayland',
  'repo:electron/electron is:issue is:open BrowserView Linux Wayland',
  'repo:electron/electron is:issue is:open Wayland "WebContentsView"',
  'repo:electron/electron is:issue is:open Linux "WebContentsView"',
  'repo:electron/electron is:issue is:open "Electron 43" Wayland',
  'repo:electron/electron is:issue is:open "43.0.0" Wayland',
  'repo:electron/electron is:issue is:open "Electron Version" "43" "WebContentsView"',
  'repo:electron/electron is:issue is:open "Linux" "Offscreen"',
  'repo:electron/electron is:issue is:open "Wayland" "context menu"',
  'repo:electron/electron is:issue is:open "Wayland" "popup"',
  'repo:electron/electron is:issue is:open "Wayland" "BrowserWindow"',
  'repo:electron/electron is:issue is:open "display scaling" Linux Electron',
  'repo:electron/electron is:issue is:open "drag" "Wayland"'
];

const extraIssueNumbers = [
  // Seed with likely recent Electron 43 reports discovered by query results in prior passes is intentionally empty.
];

async function gh(path) {
  const url = path.startsWith('http') ? path : `https://api.github.com${path}`;
  const res = await fetch(url, { headers });
  const text = await res.text();
  if (!res.ok) {
    throw new Error(`${res.status} ${res.statusText} for ${url}: ${text.slice(0, 300)}`);
  }
  return JSON.parse(text);
}

function excerpt(text, terms, span = 220) {
  const hay = text || '';
  const lower = hay.toLowerCase();
  let idx = -1;
  for (const term of terms) {
    const hit = lower.indexOf(term.toLowerCase());
    if (hit !== -1 && (idx === -1 || hit < idx)) idx = hit;
  }
  if (idx === -1) return hay.replace(/\s+/g, ' ').slice(0, span);
  const start = Math.max(0, idx - Math.floor(span / 3));
  return hay.slice(start, start + span).replace(/\s+/g, ' ');
}

function inferVersion(body, title) {
  const text = `${title}\n${body || ''}`;
  const versionMatches = [...text.matchAll(/\b(?:Electron(?:\s+Version)?|electron)\D{0,20}(43(?:\.\d+){0,2}(?:-[A-Za-z0-9.-]+)?)/gi)].map(m => m[1]);
  const bare43 = [...text.matchAll(/\b43\.\d+\.\d+(?:-[A-Za-z0-9.-]+)?\b/g)].map(m => m[0]);
  const all = [...new Set([...versionMatches, ...bare43])];
  return all.join(', ');
}

function classify(issue) {
  const body = issue.body || '';
  const text = `${issue.title}\n${body}`.toLowerCase();
  const labels = issue.labels.map(l => typeof l === 'string' ? l : l.name);
  const labelsLower = labels.join(' ').toLowerCase();
  const version = inferVersion(body, issue.title);
  const confirmed43 = /\b43\.\d+\.\d+(?:-[a-z0-9.-]+)?\b/i.test(version) || /\belectron\s+43\b/i.test(`${issue.title}\n${body}`);
  const mentionsWcv = /\bwebcontentsview\b/i.test(`${issue.title}\n${body}`);
  const mentionsBrowserView = /\bbrowserview\b/i.test(`${issue.title}\n${body}`);
  const mentionsLinux = text.includes('linux') || labelsLower.includes('linux');
  const mentionsWayland = text.includes('wayland') || labelsLower.includes('wayland');
  const keywords = [];
  for (const k of ['crash', 'segfault', 'freeze', 'hang', 'input', 'keyboard', 'mouse', 'context menu', 'popup', 'scale', 'dpi', 'transparent', 'offscreen', 'drag', 'resize', 'focus', 'capture']) {
    if (text.includes(k)) keywords.push(k);
  }
  return {
    source: 'GitHub electron/electron issues',
    sourceType: 'primary',
    observedAt: new Date().toISOString(),
    number: issue.number,
    title: issue.title,
    url: issue.html_url,
    state: issue.state,
    createdAt: issue.created_at,
    updatedAt: issue.updated_at,
    labels,
    reportedVersion: version,
    targetVersionApplicability: confirmed43 ? 'confirmed' : 'unknown',
    platform: [mentionsLinux && 'Linux', mentionsWayland && 'Wayland'].filter(Boolean).join('/') || 'unknown',
    status: issue.state,
    claim: [
      mentionsWcv ? 'mentions WebContentsView' : '',
      mentionsBrowserView ? 'mentions BrowserView' : '',
      mentionsLinux ? 'mentions Linux' : '',
      mentionsWayland ? 'mentions Wayland' : '',
      keywords.length ? `keywords: ${keywords.join(', ')}` : ''
    ].filter(Boolean).join('; '),
    evidenceStrength: confirmed43 && (mentionsWcv || mentionsWayland || mentionsLinux) ? 'high' : (mentionsWcv || mentionsWayland || mentionsLinux ? 'medium' : 'low'),
    excerpt: excerpt(body, ['Electron Version', 'WebContentsView', 'BrowserView', 'Linux', 'Wayland', 'Description', 'Steps']),
    bodySample: excerpt(body, ['43.', 'Wayland', 'WebContentsView', 'Linux'], 800),
    comments: issue.comments
  };
}

async function main() {
  writeFileSync(evidencePath, '');
  const seen = new Map();
  const querySummaries = [];

  for (const q of queries) {
    const path = `/search/issues?q=${encodeURIComponent(q)}&sort=updated&order=desc&per_page=20`;
    const data = await gh(path);
    querySummaries.push({ q, total_count: data.total_count, returned: data.items.length });
    for (const item of data.items) {
      if (!seen.has(item.number)) seen.set(item.number, item);
    }
    await delay(700);
  }

  for (const num of extraIssueNumbers) {
    if (!seen.has(num)) {
      const issue = await gh(`/repos/electron/electron/issues/${num}`);
      seen.set(num, issue);
      await delay(250);
    }
  }

  const records = [...seen.values()].map(classify)
    .filter(r => {
      const text = `${r.title} ${r.claim} ${r.excerpt}`.toLowerCase();
      return text.includes('webcontentsview') || text.includes('browserview') || text.includes('wayland') || text.includes('linux');
    })
    .sort((a, b) => {
      const a43 = a.targetVersionApplicability === 'confirmed' ? 1 : 0;
      const b43 = b.targetVersionApplicability === 'confirmed' ? 1 : 0;
      if (a43 !== b43) return b43 - a43;
      return new Date(b.updatedAt) - new Date(a.updatedAt);
    });

  for (const record of records) appendFileSync(evidencePath, JSON.stringify(record) + '\n');
  writeFileSync(metricsPath, JSON.stringify({ queries: querySummaries, uniqueIssues: seen.size, records: records.length }, null, 2));
  console.log(JSON.stringify({ ok: true, records: records.length, artifacts: { evidence: evidencePath, metrics: metricsPath }, gaps: [], durationMs: 0 }));
}

main().catch(err => {
  console.error(JSON.stringify({ ok: false, error: err.message, stack: err.stack }));
  process.exit(1);
});

